+namespace DocSummary.Services;
+
+/// <summary>
+/// Extractive summarizer that selects the most important sentences from a document.
+/// Sentences are scored by word frequency, and the top-ranked ones are returned
+/// in their original order.
+/// </summary>
+public class ExtractiveSummarizer : IDocumentSummarizer
+{
+    private const int MaxSentences = 5;
+
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
+        "in", "on", "at", "to", "for", "of", "with", "by", "it", "this",
+        "that", "from", "as", "be", "has", "have", "had", "do", "does",
+        "did", "will", "would", "could", "should", "may", "might", "not",
+        "no", "so", "if", "then", "than", "too", "very", "can", "just",
+        "about", "into", "over", "after", "before", "between", "under",
+        "again", "there", "here", "where", "when", "how", "all", "each",
+        "every", "both", "few", "more", "most", "other", "some", "such",
+        "only", "own", "same", "also", "been", "being", "its", "which"
+    };
+
+    public string Summarize(string documentText)
+    {
+        var sentences = SplitIntoSentences(documentText);
+        if (sentences.Count <= MaxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = ComputeWordFrequencies(sentences);
+        var scored = ScoreSentences(sentences, wordFrequencies);
+
+        // Pick top sentences but preserve original order
+        var topIndices = scored
+            .OrderByDescending(s => s.Score)
+            .Take(MaxSentences)
+            .Select(s => s.Index)
+            .Order()
+            .ToList();
+
+        return string.Join(" ", topIndices.Select(i => sentences[i]));
+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        return text
+            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
+            .Where(s => s.Length > 0)
+            .Select(s => s + ".")
+            .ToList();
+    }
+
+    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in Tokenize(sentence))
+            {
+                if (!StopWords.Contains(word))
+                    freq[word] = freq.GetValueOrDefault(word) + 1;
+            }
+        }
+        return freq;
+    }
